import os
import sys
import boto3

def prompt(msg, default=None):
    if default is None:
        s = input(msg).strip()
        return s
    s = input(f"{msg} [{default}]: ").strip()
    return s if s else default

def iter_endpoints_from_input():
    print("Enter HTTPS endpoints (one per line). Empty line to finish.")
    while True:
        line = input().strip()
        if not line:
            break
        yield line

def subscribe_endpoints(sns, topic_arn, endpoints, return_subscription_arn=False):
    results = []
    for endpoint in endpoints:
        resp = sns.subscribe(
            TopicArn=topic_arn,
            Protocol="https",
            Endpoint=endpoint,
            ReturnSubscriptionArn=return_subscription_arn
        )
        results.append((endpoint, resp.get("SubscriptionArn")))
    return results

def main():
    topic_arn = os.environ.get("SNS_TOPIC_ARN") or prompt("SNS TopicArn")
    region = os.environ.get("AWS_REGION") or os.environ.get("AWS_DEFAULT_REGION") or prompt("AWS region", "us-east-1")
    profile = os.environ.get("AWS_PROFILE")

    session_kwargs = {}
    if profile:
        session_kwargs["profile_name"] = profile
    session = boto3.Session(region_name=region, **session_kwargs)
    sns = session.client("sns")

    endpoints = list(iter_endpoints_from_input())
    if not endpoints:
        print("No endpoints provided.", file=sys.stderr)
        sys.exit(1)

    return_subscription_arn = (prompt("ReturnSubscriptionArn? (y/N)", "N").lower() in ("y", "yes"))
    results = subscribe_endpoints(sns, topic_arn, endpoints, return_subscription_arn=return_subscription_arn)

    for endpoint, sub_arn in results:
        if sub_arn:
            print(f"{endpoint}\t{sub_arn}")
        else:
            print(f"{endpoint}\t(subscribed)")

if __name__ == "__main__":
    main()